#include <stdio.h>
#include <stdlib.h>

typedef struct {int r,c;} Cell;

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,M; scanf("%d %d",&N,&M);
        char **grid = (char**)malloc(N*sizeof(char*));
        for(int i=0;i<N;i++){
            grid[i]=(char*)malloc((M+1)*sizeof(char));
            scanf("%s",grid[i]);
        }
        char *vis = (char*)calloc(N*M, sizeof(char));
        int *sizes = (int*)malloc(N*M*sizeof(int));
        int szCount=0;
        int dr[4]={-1,1,0,0};
        int dc[4]={0,0,-1,1};
        Cell *stack = (Cell*)malloc(N*M*sizeof(Cell));
        for(int i=0;i<N;i++){
            for(int j=0;j<M;j++){
                if(grid[i][j]=='1' && !vis[i*M+j]){
                    int top=0; long long curSize=0;
                    stack[top++] = (Cell){i,j};
                    vis[i*M+j]=1;
                    while(top){
                        Cell cur = stack[--top];
                        curSize++;
                        for(int d=0;d<4;d++){
                            int nr=cur.r+dr[d], nc=cur.c+dc[d];
                            if(nr>=0 && nr<N && nc>=0 && nc<M && grid[nr][nc]=='1' && !vis[nr*M+nc]){
                                vis[nr*M+nc]=1;
                                stack[top++] = (Cell){nr,nc};
                            }
                        }
                    }
                    sizes[szCount++] = (int)curSize;
                }
            }
        }
        // sort descending
        qsort(sizes, szCount, sizeof(int), (int(*)(const void*,const void*))
            [](const int *a, const int *b){return (*b)-(*a);});
        long long chef=0;
        for(int i=1;i<szCount;i+=2) chef+=sizes[i];
        printf("%lld\n", chef);
        for(int i=0;i<N;i++) free(grid[i]);
        free(grid); free(vis); free(sizes); free(stack);
    }
    return 0;
}

