import java.io.*;
import java.util.*;
public class Main {
    static class FastScanner {
        private final BufferedInputStream in = new BufferedInputStream(System.in);
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') { val = val * 10 + c - '0'; c = readByte(); }
            return val * sign;
        }
        String next() throws IOException {
            int c;
            do { c = readByte(); } while (c <= ' ');
            StringBuilder sb = new StringBuilder();
            while (c > ' ') { sb.append((char)c); c = readByte(); }
            return sb.toString();
        }
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner();
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int M = fs.nextInt();
            char[][] g = new char[N][M];
            for (int i = 0; i < N; i++) {
                String s = fs.next();
                g[i] = s.toCharArray();
            }
            boolean[] vis = new boolean[N * M];
            int[] dr = {-1, 1, 0, 0};
            int[] dc = {0, 0, -1, 1};
            ArrayList<Integer> comps = new ArrayList<>();
            ArrayDeque<int[]> q = new ArrayDeque<>();
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < M; j++) {
                    if (g[i][j] == '1' && !vis[i * M + j]) {
                        int sz = 0;
                        q.clear();
                        q.add(new int[]{i, j});
                        vis[i * M + j] = true;
                        while (!q.isEmpty()) {
                            int[] cur = q.poll();
                            int r = cur[0], c = cur[1];
                            sz++;
                            for (int d = 0; d < 4; d++) {
                                int nr = r + dr[d];
                                int nc = c + dc[d];
                                if (nr >= 0 && nr < N && nc >= 0 && nc < M && g[nr][nc] == '1' && !vis[nr * M + nc]) {
                                    vis[nr * M + nc] = true;
                                    q.add(new int[]{nr, nc});
                                }
                            }
                        }
                        comps.add(sz);
                    }
                }
            }
            comps.sort(Collections.reverseOrder());
            long chef = 0;
            for (int i = 1; i < comps.size(); i += 2) chef += comps.get(i);
            out.append(chef).append('\n');
        }
        System.out.print(out.toString());
    }
}

