const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const M = Number(input[idx++]);
  const grid = [];
  for (let i = 0; i < N; i++) grid.push(input[idx++]);
  const visited = Array.from({length: N}, () => Array(M).fill(false));
  const sizes = [];
  const dr = [-1, 1, 0, 0];
  const dc = [0, 0, -1, 1];
  for (let r = 0; r < N; r++) {
    for (let c = 0; c < M; c++) {
      if (grid[r][c] === '1' && !visited[r][c]) {
        let sz = 0;
        const q = [[r, c]];
        visited[r][c] = true;
        while (q.length) {
          const [cr, cc] = q.pop();
          sz++;
          for (let d = 0; d < 4; d++) {
            const nr = cr + dr[d];
            const nc = cc + dc[d];
            if (nr >= 0 && nr < N && nc >= 0 && nc < M && grid[nr][nc] === '1' && !visited[nr][nc]) {
              visited[nr][nc] = true;
              q.push([nr, nc]);
            }
          }
        }
        sizes.push(sz);
      }
    }
  }
  sizes.sort((a, b) => b - a);
  let chef = 0;
  for (let i = 1; i < sizes.length; i += 2) chef += sizes[i];
  outputs.push(String(chef));
}
